// src/views/auth/Forget.js
import React, { useState, useRef } from "react";
import { Link, useHistory } from "react-router-dom";

export default function Forget() {
  const [email, setEmail] = useState("");
  const [isLoading, setIsLoading] = useState(false);
  const [emailSent, setEmailSent] = useState(false);
  const [focusedInput, setFocusedInput] = useState(null);
  const [rotateX, setRotateX] = useState(0);
  const [rotateY, setRotateY] = useState(0);
  const [emailError, setEmailError] = useState(false);
  const cardRef = useRef(null);
  const history = useHistory();

  const handleMouseMove = (e) => {
    if (!cardRef.current) return;
    const rect = cardRef.current.getBoundingClientRect();
    const centerX = rect.left + rect.width / 2;
    const centerY = rect.top + rect.height / 2;
    const mouseX = e.clientX - centerX;
    const mouseY = e.clientY - centerY;

    const maxRotate = 10;
    const rotateYValue = (mouseX / (rect.width / 2)) * maxRotate;
    const rotateXValue = (mouseY / (rect.height / 2)) * -maxRotate;

    setRotateY(rotateYValue);
    setRotateX(rotateXValue);
  };

  const handleMouseLeave = () => {
    setRotateX(0);
    setRotateY(0);
  };

  const validateEmail = () => {
    if (!email || !email.includes("@") || !email.includes(".")) {
      setEmailError(true);
      return false;
    }
    setEmailError(false);
    return true;
  };

  const handleSubmit = (e) => {
    e.preventDefault();

    if (validateEmail()) {
      setIsLoading(true);
      setTimeout(() => {
        setIsLoading(false);
        setEmailSent(true);
      }, 2000);
    }
  };

  const goToLogin = () => {
    history.push("/auth/login");
  };

  return (
    <div className="forget-container">
      <div className="bg-gradient"></div>
      <div className="noise-overlay"></div>
      <div className="top-glow"></div>
      <div className="bottom-glow"></div>
      <div className="glow-spot-1"></div>
      <div className="glow-spot-2"></div>

      <div className="card-wrapper">
        <div
          ref={cardRef}
          className="forget-card"
          onMouseMove={handleMouseMove}
          onMouseLeave={handleMouseLeave}
          style={{
            transform: `perspective(1500px) rotateX(${rotateX}deg) rotateY(${rotateY}deg)`,
            transition: "transform 0.1s ease-out"
          }}
        >
          <div className="card-glow"></div>

          <div className="light-beams">
            <div className="light-beam-top"></div>
            <div className="light-beam-right"></div>
            <div className="light-beam-bottom"></div>
            <div className="light-beam-left"></div>
            <div className="corner-glow corner-tl"></div>
            <div className="corner-glow corner-tr"></div>
            <div className="corner-glow corner-br"></div>
            <div className="corner-glow corner-bl"></div>
          </div>

          <div className="card-content">
            <div className="logo-wrapper">
              <div className="logo">
                <span>S</span>
                <div className="logo-glow"></div>
              </div>
            </div>

            {!emailSent ? (
              <>
                <h1 className="title">Mot de passe oublié ?</h1>
                <p className="subtitle">Entrez votre email pour réinitialiser votre mot de passe</p>

                <form onSubmit={handleSubmit}>
                  <div className="input-group">
                    <div className={`input-wrapper ${focusedInput === "email" ? "focused" : ""} ${emailError ? "error" : ""}`}>
                      <svg className="input-icon" viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                        <rect x="2" y="4" width="20" height="16" rx="2" />
                        <path d="M22 7L12 13 2 7" />
                      </svg>
                      <input
                        type="email"
                        placeholder="Adresse email"
                        value={email}
                        onChange={(e) => { setEmail(e.target.value); if (emailError) setEmailError(false); }}
                        onFocus={() => setFocusedInput("email")}
                        onBlur={() => setFocusedInput(null)}
                      />
                    </div>
                    {emailError && <p className="error-message">⚠️ Veuillez entrer une adresse email valide</p>}
                  </div>

                  <button type="submit" className="reset-btn" disabled={isLoading}>
                    {isLoading ? (
                      <div className="spinner"></div>
                    ) : (
                      <>
                        Envoyer le lien
                        <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                          <line x1="5" y1="12" x2="19" y2="12" />
                          <polyline points="12 5 19 12 12 19" />
                        </svg>
                      </>
                    )}
                  </button>

                  <p className="back-link">
                    <Link to="/auth/login">← Retour à la connexion</Link>
                  </p>
                </form>
              </>
            ) : (
              <div className="success-container">
                <div className="success-icon">📧</div>
                <h2 className="success-title">Vérifiez votre email</h2>
                <p className="success-message">
                  Un lien de réinitialisation a été envoyé à <strong>{email}</strong>
                </p>
                <p className="success-submessage">
                  Veuillez vérifier votre boîte de réception et suivre les instructions.
                </p>
                <button onClick={goToLogin} className="reset-btn">
                  Retour à la connexion
                  <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2">
                    <line x1="5" y1="12" x2="19" y2="12" />
                    <polyline points="12 5 19 12 12 19" />
                  </svg>
                </button>
              </div>
            )}
          </div>
        </div>
      </div>

