          transition: transform 0.1s ease-out;
        }

        .card-glow {
          position: absolute;
          inset: -1px;
          border-radius: 24px;
          opacity: 0;
          transition: opacity 0.7s ease;
          background: radial-gradient(circle at center, rgba(255,255,255,0.1), transparent);
        }

        .forget-card:hover .card-glow {
          opacity: 0.7;
        }

        .light-beams {
          position: absolute;
          inset: -1px;
          border-radius: 24px;
          overflow: hidden;
          pointer-events: none;
        }

        .light-beam-top {
          position: absolute;
          top: 0;
          left: 0;
