          font-size: 20px;
          font-weight: bold;
          background: linear-gradient(180deg, white, rgba(255,255,255,0.7));
          -webkit-background-clip: text;
          background-clip: text;
          color: transparent;
        }

        .logo-glow {
          position: absolute;
          inset: 0;
          background: linear-gradient(135deg, rgba(255,255,255,0.1), transparent);
          opacity: 0.5;
        }

        .title {
          text-align: center;
          font-size: 24px;
          font-weight: bold;
          background: linear-gradient(180deg, white, rgba(255,255,255,0.8));
          -webkit-background-clip: text;
          background-clip: text;
          color: transparent;
          margin-bottom: 8px;
        }

        .subtitle {
          text-align: center;
          font-size: 13px;
          color: rgba(255, 255, 255, 0.6);
          margin-bottom: 28px;
        }

        .input-group {
          margin-bottom: 24px;
        }

        .input-wrapper {
          position: relative;
          display: flex;
